import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer style={styles.footerContainer}>
            <div style={styles.footerContentWrapper}>
                {/* Texto de Copyright principal */}
                <p style={styles.copyrightMainText}>
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                    <span style={styles.teamName}> Trinity Team</span>.
                </p>

                {/* Contenido de las 3 columnas */}
                <div style={styles.gridContainer}>

                    {/* Columna 1: Navegación (antes "Más información") */}
                    <div style={styles.gridColumn}>
                        <h3 style={styles.sectionTitle}>Navegación</h3>
                        <ul style={styles.linkList}>
                            <li><Link to="/" style={styles.link}>Inicio</Link></li>
                            <li><Link to="/login" style={styles.link}>Login</Link></li>
                            <li><Link to="/register" style={styles.link}>Registro</Link></li>
                            {/* Ajustamos los links aquí para que coincidan con tu ejemplo */}
                        </ul>
                    </div>

                    {/* Columna 2: Redes Sociales */}
                    <div style={styles.gridColumnCenter}>
                        <h3 style={styles.sectionTitle}>Redes Sociales</h3>
                        <div style={styles.socialIcons}>
                            {/* Reemplaza los href y src con tus enlaces e imágenes reales */}
                            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
                            </a>
                        </div>
                    </div>

                    {/* Columna 3: Sobre el Repositorio */}
                    <div style={styles.gridColumn}>
                        <h3 style={styles.sectionTitle}>Sobre el Repositorio</h3>
                        <p style={styles.aboutText}>
                            Plataforma digital para consulta, preservación y análisis de documentos históricos bolivianos. Proyecto del Bicentenario 2025.
                        </p>
                    </div>

                </div>

                {/* Cita final */}
                <p style={styles.quoteText}>
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

            </div>
        </footer>
    );
};

const styles = {
    footerContainer: {
        // Fondo con la imagen de footer2.png de public/media
        backgroundImage: "url('/media/footer2.png')", // Ruta relativa a la carpeta 'public'
        backgroundSize: 'cover', // Cubrir toda el área
        backgroundPosition: 'center', // Centrar la imagen
        backgroundRepeat: 'no-repeat', // No repetir la imagen
        backgroundColor: '#F8F6F1', // Color de fondo de respaldo (similar a yellow-50)
        color: '#4a4a4a', // Texto general (similar a neutral-700)
        fontFamily: "'Inter', 'ui-sans-serif', 'system-ui', sans-serif", // Fuente similar a la de Tailwind
        padding: '20px 0', // Padding vertical, padding horizontal en el wrapper
        marginTop: 'auto', // Para que se pegue al final de la página
        boxShadow: 'inset 0 2px 4px rgba(0,0,0,0.06)', // Sombra interna sutil
        transition: 'background-color 0.3s ease, color 0.3s ease', // Transiciones suaves
        fontSize: '0.9rem', // Tamaño base de la fuente
    },
    footerContentWrapper: {
        maxWidth: '1024px', // max-w-6xl (1152px) o ajustado
        margin: '0 auto',
        padding: '0 24px', // px-6
        textAlign: 'center', // Default text-center
    },
    copyrightMainText: {
        fontSize: '0.875rem', // text-sm
        color: '#4a4a4a', // text-neutral-700
        marginBottom: '24px', // mb-6
        lineHeight: '1.5', // leading-snug
        textAlign: 'center',
    },
    teamName: {
        fontWeight: '600', // font-semibold
        color: '#333', // text-neutral-800
    },
    gridContainer: {
        display: 'grid',
        gridTemplateColumns: 'repeat(1, minmax(0, 1fr))', // grid-cols-1
        gap: '32px', // gap-8
        textAlign: 'center', // text-center
        marginBottom: '32px', // mb-8
        // Media query para sm:grid-cols-3 y sm:text-left
        '@media (min-width: 640px)': { // sm breakpoint
            gridTemplateColumns: 'repeat(3, minmax(0, 1fr))',
            textAlign: 'left',
        },
    },
    gridColumn: {
        // Flexbox para centrar items en sm:items-start si es necesario
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center', // items-center
        '@media (min-width: 640px)': {
            alignItems: 'flex-start', // sm:items-start
        },
    },
    gridColumnCenter: { // Específico para "Redes Sociales"
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center', // Siempre centrado para los íconos
    },
    sectionTitle: {
        fontSize: '1rem', // text-base
        fontWeight: '600', // font-semibold
        color: '#333', // text-neutral-800
        marginBottom: '12px', // mb-3
    },
    linkList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: '1.5', // space-y-2 (aproximado)
    },
    link: {
        textDecoration: 'none',
        color: '#555', // text-neutral-600
        transition: 'color 0.2s ease', // transition
        display: 'inline-block', // Necesario para hover effects
        '&:hover': {
            color: '#d97706', // hover:text-yellow-600 (color similar)
        },
    },
    socialIcons: {
        display: 'flex',
        justifyContent: 'center', // Centrar íconos
        gap: '16px', // gap-4 (aproximado)
        marginTop: '8px', // Algunos estilos añaden margin top implícito
        color: '#4a4a4a', // text-neutral-700
    },
    socialIconLink: {
        textDecoration: 'none',
        display: 'inline-block',
    },
    socialIconImage: {
        width: '24px', // Tamaño de los iconos, ajusta si es necesario
        height: '24px',
        opacity: 0.8, // Para un efecto más suave
        transition: 'opacity 0.2s ease, transform 0.2s ease',
        '&:hover': {
            opacity: 1,
            transform: 'scale(1.1)',
        },
    },
    aboutText: {
        fontSize: '0.875rem', // text-sm
        color: '#666', // text-neutral-600
        lineHeight: '1.625', // leading-relaxed
        textAlign: 'center', // text-center
        '@media (min-width: 640px)': {
            textAlign: 'left', // sm:text-left
        },
    },
    quoteText: {
        textAlign: 'center', // text-center
        fontSize: '0.75rem', // text-xs
        color: '#777', // text-neutral-500
        letterSpacing: '0.025em', // tracking-wide
        fontStyle: 'italic', // italic
        marginTop: '24px', // mt-6
        paddingBottom: '10px', // Un poco de espacio al final
    },
};

export default Footer;
